const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_API_KEY = 'sb_publishable_HsIkelEZaIr0VauiB3GgIQ_59XJRoWc';

return [{ json: { SUPABASE_URL, SUPABASE_API_KEY } }];

const httpSelf = this;
const items = $input.all();
const settings = items[0].json;

const SUPABASE_URL = settings.SUPABASE_URL;
const SUPABASE_API_KEY = settings.SUPABASE_API_KEY;

const now = new Date().toISOString();

// 1. Query ALL published_content where status = 'scheduled' (no user_id filter — cron processes all users)
const scheduled = await httpSelf.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/published_content_v2?status=eq.scheduled&select=*`,
  headers: {
    'apikey': SUPABASE_API_KEY,
    'Authorization': `Bearer ${SUPABASE_API_KEY}`,
    'Content-Type': 'application/json'
  }
});

const publishedItems = [];
// Track per-user email config so we only fetch once per user
const userEmailCache = {};

for (const item of scheduled) {
  // 2. Check if schedule_date is due
  const metadata = typeof item.metadata === 'string' ? JSON.parse(item.metadata) : (item.metadata || {});
  const scheduleDate = metadata.schedule_date;

  if (!scheduleDate) continue;

  // Compare ISO date strings — if schedule_date <= now, it's due
  if (scheduleDate <= now) {
    const itemUserId = item.user_id || null;

    // 3. Snapshot into content_versions before publishing
    try {
      const vUrl = itemUserId
        ? `${SUPABASE_URL}/rest/v1/content_versions_v2?content_id=eq.${item.id}&user_id=eq.${itemUserId}&order=version_number.desc&limit=1&select=version_number`
        : `${SUPABASE_URL}/rest/v1/content_versions_v2?content_id=eq.${item.id}&order=version_number.desc&limit=1&select=version_number`;
      const vResp = await httpSelf.helpers.httpRequest({
        method: 'GET',
        url: vUrl,
        headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}`, 'Content-Type': 'application/json' }
      });
      const maxV = Array.isArray(vResp) && vResp.length > 0 ? vResp[0].version_number : 0;
      const versionBody = {
        content_id: item.id,
        version_number: maxV + 1,
        content_text: item.content_text || '',
        changed_by: 'scheduler',
        change_note: 'Auto-snapshot before scheduled publish'
      };
      if (itemUserId) versionBody.user_id = itemUserId;
      await httpSelf.helpers.httpRequest({
        method: 'POST',
        url: `${SUPABASE_URL}/rest/v1/content_versions_v2`,
        headers: {
          'apikey': SUPABASE_API_KEY,
          'Authorization': `Bearer ${SUPABASE_API_KEY}`,
          'Content-Type': 'application/json',
          'Prefer': 'return=minimal'
        },
        body: versionBody,
        json: true
      });
    } catch (e) {
      // Log but don't block publishing
      console.log(`Version snapshot failed for ${item.id}: ${e.message}`);
    }

    // 4. PATCH status to 'published', set published_at, update metadata
    const updatedMetadata = { ...metadata, auto_published: true, auto_published_at: now };
    delete updatedMetadata.schedule_date;

    await httpSelf.helpers.httpRequest({
      method: 'PATCH',
      url: `${SUPABASE_URL}/rest/v1/published_content_v2?id=eq.${item.id}`,
      headers: {
        'apikey': SUPABASE_API_KEY,
        'Authorization': `Bearer ${SUPABASE_API_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: {
        status: 'published',
        published_at: now,
        metadata: updatedMetadata
      },
      json: true
    });

    // 5. Fetch per-user email config (cached)
    let recipientEmail = 'eric@agileadtesting.com';
    let bccEmail = '';
    if (itemUserId) {
      if (!userEmailCache[itemUserId]) {
        try {
          const cfgRows = await httpSelf.helpers.httpRequest({
            method: 'GET',
            url: `${SUPABASE_URL}/rest/v1/app_config_v2?key=in.(recipient_email,bcc_email)&user_id=eq.${itemUserId}&select=key,value`,
            headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
          });
          const cfg = { recipientEmail: 'eric@agileadtesting.com', bccEmail: '' };
          for (const row of cfgRows) {
            if (row.key === 'recipient_email') cfg.recipientEmail = row.value;
            if (row.key === 'bcc_email') cfg.bccEmail = row.value;
          }
          userEmailCache[itemUserId] = cfg;
        } catch (e) {
          userEmailCache[itemUserId] = { recipientEmail: 'eric@agileadtesting.com', bccEmail: '' };
        }
      }
      recipientEmail = userEmailCache[itemUserId].recipientEmail;
      bccEmail = userEmailCache[itemUserId].bccEmail;
    }

    publishedItems.push({
      id: item.id,
      title: item.title || 'Untitled',
      content_type: item.content_type || 'unknown',
      schedule_date: scheduleDate,
      user_id: itemUserId,
      recipient_email: recipientEmail,
      bcc_email: bccEmail
    });
  }
}

// 6. Build summary
const publishedCount = publishedItems.length;
const sendNotification = publishedCount > 0;

let notificationBody = '';
let notificationSubject = '';
let result = '';
// Use first item's email as default (multi-user notification could be extended later)
let recipientEmail = publishedItems.length > 0 ? publishedItems[0].recipient_email : 'eric@agileadtesting.com';
let bccEmail = publishedItems.length > 0 ? publishedItems[0].bcc_email : '';

if (sendNotification) {
  const listItems = publishedItems.map(p =>
    `<li><strong>${p.title}</strong> (${p.content_type}) \u2014 scheduled for ${p.schedule_date}</li>`
  ).join('\n  ');

  notificationBody = `<h2>Scheduled Content Published</h2>
<p>${publishedCount} item(s) automatically published:</p>
<ul>
  ${listItems}
</ul>`;

  notificationSubject = `Auto-Published: ${publishedCount} scheduled item(s)`;
  result = `Published ${publishedCount} scheduled item(s): ${publishedItems.map(p => p.title).join(', ')}`;
} else {
  result = 'No scheduled content due for publishing.';
  notificationSubject = '';
  notificationBody = '';
}

return [{
  json: {
    result,
    published_count: publishedCount,
    send_notification: sendNotification,
    notification_subject: notificationSubject,
    notification_body: notificationBody,
    recipient_email: recipientEmail,
    bcc_email: bccEmail
  }
}];
